import { Component, HostListener, OnDestroy } from '@angular/core';
import { CommonModule } from '@angular/common';

type Direction = 'UP' | 'DOWN' | 'LEFT' | 'RIGHT';
interface Point { x: number; y: number }

const BOARD_SIZE = 14;
const STEP_MS = 140;
const INITIAL_SNAKE: Point[] = [
  { x: 6, y: 7 },
  { x: 5, y: 7 },
  { x: 4, y: 7 }
];
const INITIAL_FOOD: Point = { x: 8, y: 7 };

const DIRECTION_DELTA: Record<Direction, Point> = {
  UP: { x: 0, y: -1 },
  DOWN: { x: 0, y: 1 },
  LEFT: { x: -1, y: 0 },
  RIGHT: { x: 1, y: 0 }
};

const OPPOSITE: Record<Direction, Direction> = {
  UP: 'DOWN',
  DOWN: 'UP',
  LEFT: 'RIGHT',
  RIGHT: 'LEFT'
};

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.css']
})
export class AppComponent implements OnDestroy {
  readonly boardSize = BOARD_SIZE;

  snake: Point[] = INITIAL_SNAKE.map((point) => ({ ...point }));
  direction: Direction = 'RIGHT';
  pendingDirection: Direction = 'RIGHT';
  food: Point = { ...INITIAL_FOOD };
  isRunning = false;
  isGameOver = false;
  score = 0;

  private timerId: ReturnType<typeof setInterval> | null = null;

  get length(): number {
    return this.snake.length;
  }

  get statusLabel(): string {
    if (this.isGameOver) return 'Game over';
    return this.isRunning ? 'Running' : 'Paused';
  }

  @HostListener('window:keydown', ['$event'])
  onKeydown(event: KeyboardEvent): void {
    const key = String(event.key || '').toLowerCase();

    // TODO: map Arrow keys + WASD to direction.
    // TODO: prevent immediate reverse direction via OPPOSITE map.
    // TODO: Space toggles start/pause when game is not over.
    // TODO: Enter resets after game over.

    void key;
  }

  toggleRunning(): void {
    if (this.isGameOver) return;
    this.isRunning ? this.pause() : this.start();
  }

  start(): void {
    // TODO: set running true and start one interval tick every STEP_MS.
  }

  pause(): void {
    // TODO: stop interval and set running false.
  }

  reset(): void {
    // TODO: restore initial snake/direction/food/score/running/gameOver.
  }

  isSnake(x: number, y: number): boolean {
    return this.snake.some((point) => point.x === x && point.y === y);
  }

  isHead(x: number, y: number): boolean {
    const head = this.snake[0];
    return head.x === x && head.y === y;
  }

  isFood(x: number, y: number): boolean {
    return this.food.x === x && this.food.y === y;
  }

  trackByIndex(index: number): number {
    return index;
  }

  ngOnDestroy(): void {
    this.clearTimer();
  }

  private tick(): void {
    // TODO: move one step using pendingDirection.
    // TODO: detect wall collision and self collision -> end game.
    // TODO: if food eaten -> grow snake body + score++ + respawn food.
    // TODO: if no food -> pop tail.
    // TODO: sync direction with pendingDirection after successful move.
  }

  private pointKey(point: Point): string {
    return String(point.x) + ',' + String(point.y);
  }

  private randomFood(snake: Point[]): Point {
    const occupied = new Set(snake.map((point) => this.pointKey(point)));
    const free: Point[] = [];

    for (let y = 0; y < this.boardSize; y += 1) {
      for (let x = 0; x < this.boardSize; x += 1) {
        const key = String(x) + ',' + String(y);
        if (!occupied.has(key)) free.push({ x, y });
      }
    }

    if (!free.length) return { x: 0, y: 0 };
    return free[Math.floor(Math.random() * free.length)];
  }

  private moveHead(head: Point, direction: Direction): Point {
    const delta = DIRECTION_DELTA[direction];
    return {
      x: head.x + delta.x,
      y: head.y + delta.y
    };
  }

  private outOfBounds(point: Point): boolean {
    return point.x < 0 || point.y < 0 || point.x >= this.boardSize || point.y >= this.boardSize;
  }

  private clearTimer(): void {
    if (this.timerId) {
      clearInterval(this.timerId);
      this.timerId = null;
    }
  }
}

