import { TestBed, discardPeriodicTasks, fakeAsync, tick } from '@angular/core/testing';
import { AppComponent } from './app.component';

const STEP_MS = 140;

type TestAppComponent = AppComponent & {
  snake: Array<{ x: number; y: number }>;
  direction: 'UP' | 'DOWN' | 'LEFT' | 'RIGHT';
  pendingDirection: 'UP' | 'DOWN' | 'LEFT' | 'RIGHT';
  food: { x: number; y: number };
};

function createComponent() {
  TestBed.configureTestingModule({
    imports: [AppComponent]
  });

  const fixture = TestBed.createComponent(AppComponent);
  fixture.detectChanges();
  return { fixture, component: fixture.componentInstance as TestAppComponent };
}

function press(component: AppComponent, key: string): void {
  component.onKeydown(new KeyboardEvent('keydown', { key }));
}

describe('Angular Snake Game', () => {
  it('renders a fixed grid board', () => {
    const { fixture } = createComponent();

    expect(fixture.nativeElement.querySelectorAll('.cell').length).toBe(196);

    fixture.destroy();
  });

  it('renders the initial snake and deterministic food', () => {
    const { fixture, component } = createComponent();

    expect(component.snake).toEqual([
      { x: 6, y: 7 },
      { x: 5, y: 7 },
      { x: 4, y: 7 }
    ]);
    expect(component.food).toEqual({ x: 8, y: 7 });
    expect(fixture.nativeElement.querySelectorAll('.cell--snake').length).toBe(3);
    expect(fixture.nativeElement.querySelectorAll('.cell--food').length).toBe(1);

    fixture.destroy();
  });

  it('does not move synchronously before the first timer tick', fakeAsync(() => {
    const { fixture, component } = createComponent();
    const initialHead = { ...component.snake[0] };

    component.start();
    tick(STEP_MS - 1);

    expect(component.snake[0]).toEqual(initialHead);

    fixture.destroy();
    discardPeriodicTasks();
  }));

  it('moves the snake one cell per timer tick', fakeAsync(() => {
    const { fixture, component } = createComponent();

    component.start();
    tick(STEP_MS);

    expect(component.snake[0]).toEqual({ x: 7, y: 7 });
    expect(component.snake).toEqual([
      { x: 7, y: 7 },
      { x: 6, y: 7 },
      { x: 5, y: 7 }
    ]);

    fixture.destroy();
    discardPeriodicTasks();
  }));

  it('changes direction on valid keyboard input', fakeAsync(() => {
    const { fixture, component } = createComponent();

    component.start();
    press(component, 'ArrowDown');
    tick(STEP_MS);

    expect(component.snake[0]).toEqual({ x: 6, y: 8 });
    expect(component.direction).toBe('DOWN');

    fixture.destroy();
    discardPeriodicTasks();
  }));

  it('ignores immediate reverse direction', fakeAsync(() => {
    const { fixture, component } = createComponent();

    component.start();
    press(component, 'ArrowLeft');
    tick(STEP_MS);

    expect(component.snake[0]).toEqual({ x: 7, y: 7 });
    expect(component.direction).toBe('RIGHT');
    expect(component.isGameOver).toBeFalse();

    fixture.destroy();
    discardPeriodicTasks();
  }));

  it('grows the snake, increments score, and respawns food outside the snake body', fakeAsync(() => {
    const { fixture, component } = createComponent();

    component.food = { x: 7, y: 7 };
    component.start();
    tick(STEP_MS);

    expect(component.score).toBe(1);
    expect(component.snake.length).toBe(4);
    expect(component.snake[0]).toEqual({ x: 7, y: 7 });
    expect(component.snake.some((part) => part.x === component.food.x && part.y === component.food.y)).toBeFalse();

    fixture.destroy();
    discardPeriodicTasks();
  }));

  it('ends the game on wall collision and stops movement', fakeAsync(() => {
    const { fixture, component } = createComponent();

    component.snake = [
      { x: 13, y: 7 },
      { x: 12, y: 7 },
      { x: 11, y: 7 }
    ];
    component.direction = 'RIGHT';
    component.pendingDirection = 'RIGHT';

    component.start();
    tick(STEP_MS);

    expect(component.isGameOver).toBeTrue();
    expect(component.snake[0]).toEqual({ x: 13, y: 7 });
    expect(component.isRunning).toBeFalse();

    tick(STEP_MS * 2);
    expect(component.snake[0]).toEqual({ x: 13, y: 7 });

    fixture.destroy();
    discardPeriodicTasks();
  }));

  it('ends the game on self collision', fakeAsync(() => {
    const { fixture, component } = createComponent();

    component.snake = [
      { x: 5, y: 5 },
      { x: 5, y: 6 },
      { x: 6, y: 6 },
      { x: 6, y: 5 },
      { x: 7, y: 5 }
    ];
    component.direction = 'RIGHT';
    component.pendingDirection = 'RIGHT';

    component.start();
    tick(STEP_MS);

    expect(component.isGameOver).toBeTrue();
    expect(component.snake[0]).toEqual({ x: 5, y: 5 });
    expect(component.isRunning).toBeFalse();

    fixture.destroy();
    discardPeriodicTasks();
  }));

  it('reset returns the game to the initial state', fakeAsync(() => {
    const { fixture, component } = createComponent();

    component.food = { x: 7, y: 7 };
    component.start();
    tick(STEP_MS);
    component.reset();

    expect(component.score).toBe(0);
    expect(component.snake).toEqual([
      { x: 6, y: 7 },
      { x: 5, y: 7 },
      { x: 4, y: 7 }
    ]);
    expect(component.food).toEqual({ x: 8, y: 7 });
    expect(component.direction).toBe('RIGHT');
    expect(component.pendingDirection).toBe('RIGHT');
    expect(component.isRunning).toBeFalse();
    expect(component.isGameOver).toBeFalse();

    fixture.destroy();
    discardPeriodicTasks();
  }));

  it('cleans up the timer when the component is destroyed', fakeAsync(() => {
    const clearIntervalSpy = spyOn(window, 'clearInterval').and.callThrough();
    const { fixture, component } = createComponent();

    component.start();
    fixture.destroy();

    expect(clearIntervalSpy).toHaveBeenCalled();
    discardPeriodicTasks();
  }));
});
